CREATE PROCEDURE [dbo].[spProductUnitUpdate] @UnitId INT, @UnitCode NVARCHAR(50), @UnitName NVARCHAR(100), @UnitSymbol NVARCHAR(30), @AllowDecimal BIT, @IsBaseUnit BIT, @Description NVARCHAR(500), @IsActive BIT, @UpdatedByUserId INT AS BEGIN SET NOCOUNT ON; UPDATE [dbo].[ProductUnit] SET UnitCode=@UnitCode, UnitName=@UnitName, UnitSymbol=ISNULL(@UnitSymbol,N''), AllowDecimal=@AllowDecimal, IsBaseUnit=@IsBaseUnit, Description=ISNULL(@Description,N''), IsActive=@IsActive, UpdatedByUserId=NULLIF(@UpdatedByUserId,0), UpdatedDate=SYSUTCDATETIME() WHERE UnitId=@UnitId; END;
